~/.config/omarchy/current/theme/obsidian.text:
/* Omarchy Theme for Obsidian */

.theme-dark, .theme-light {
  /* Core colors */
  --background-primary: #1a1b26;
  --background-primary-alt: #1a1b26;
  --background-secondary: #1a1b26;
  --background-secondary-alt: #1a1b26;
  --text-normal: #a9b1d6;

  /* Selection colors */
  --text-selection: #7aa2f7;

  /* Border color */
  --background-modifier-border: #444b6a;

  /* Semantic heading colors */
  --text-title-h1: #f7768e;
  --text-title-h2: #9ece6a;
  --text-title-h3: #e0af68;
  --text-title-h4: #7aa2f7;
  --text-title-h5: #ad8ee6;
  --text-title-h6: #ad8ee6;

  /* Links and accents */
  --text-link: #7aa2f7;
  --text-accent: #7aa2f7;
  --text-accent-hover: #7aa2f7;
  --interactive-accent: #7aa2f7;
  --interactive-accent-hover: #7aa2f7;

  /* Muted text */
  --text-muted: color-mix(in srgb, #a9b1d6 70%, transparent);
  --text-faint: color-mix(in srgb, #a9b1d6 55%, transparent);

  /* Code */
  --code-normal: #449dab;

  /* Errors and success */
  --text-error: #f7768e;
  --text-error-hover: #f7768e;
  --text-success: #9ece6a;

  /* Tags */
  --tag-color: #449dab;
  --tag-background: #444b6a;

  /* Graph */
  --graph-line: #444b6a;
  --graph-node: #7aa2f7;
  --graph-node-focused: #7aa2f7;
  --graph-node-tag: #449dab;
  --graph-node-attachment: #9ece6a;
}

/* Headers */
.cm-header-1, .markdown-rendered h1 { color: var(--text-title-h1); }
.cm-header-2, .markdown-rendered h2 { color: var(--text-title-h2); }
.cm-header-3, .markdown-rendered h3 { color: var(--text-title-h3); }
.cm-header-4, .markdown-rendered h4 { color: var(--text-title-h4); }
.cm-header-5, .markdown-rendered h5 { color: var(--text-title-h5); }
.cm-header-6, .markdown-rendered h6 { color: var(--text-title-h6); }

/* Code blocks */
.markdown-rendered code {
  color: #449dab;
}

/* Syntax highlighting */
.cm-s-obsidian span.cm-keyword { color: #f7768e; }
.cm-s-obsidian span.cm-string { color: #9ece6a; }
.cm-s-obsidian span.cm-number { color: #e0af68; }
.cm-s-obsidian span.cm-comment { color: #444b6a; }
.cm-s-obsidian span.cm-operator { color: #7aa2f7; }
.cm-s-obsidian span.cm-def { color: #7aa2f7; }

/* Links */
.markdown-rendered a {
  color: var(--text-link);
}

/* Blockquotes */
.markdown-rendered blockquote {
  border-left-color: #7aa2f7;
}

/* Active elements */
.workspace-leaf.mod-active .workspace-leaf-header-title {
  color: var(--interactive-accent);
}

.nav-file-title.is-active {
  color: var(--interactive-accent);
}

/* Search results */
.search-result-file-title {
  color: var(--interactive-accent);
}

